import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/base_classes/l_system_module_base.dart';

/// Shared behavior contract for generated L-system module smoke tests.
void smokeTestLSystemModule({
  required String name,
  required LSystemModule Function() createModule,
  required String expectedId,
  required String expectedShader,
}) {
  test('$name instantiates', () {
    final module = createModule();
    expect(module.id, expectedId);
    expect(module.shader, expectedShader);
  });

  test('$name presets are well-formed', () {
    final module = createModule();
    expect(module.presets, isNotEmpty);
    for (final preset in module.presets) {
      final dynamic typedPreset = preset;
      expect(typedPreset.id, isNotEmpty);
      expect(typedPreset.name, isNotEmpty);
    }
  });

  test('$name metadata is consistent', () {
    final module = createModule();
    final dynamic metadata = module.metadata;
    expect(metadata.id, module.id);
  });
}

